import{_ as a,o as e,c as o,a2 as i}from"./chunks/framework.B8zgMDLd.js";const m=JSON.parse('{"title":"Git","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/git.md","filePath":"concepts/git.md"}'),r={name:"concepts/git.md"};function n(s,t,l,c,h,d){return e(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="git" tabindex="-1">Git <a class="header-anchor" href="#git" aria-label="Permalink to &quot;Git&quot;">​</a></h1><p>Git is Tolaria&#39;s recommended history and sync layer. Tolaria can work with plain Markdown folders, and Git unlocks local history, recovery, remote backup, and multi-device workflows when you want them.</p><p>Tolaria acts as a lightweight Git client for your vault. You can review changes, commit, pull, push, and inspect history without leaving the app.</p><h2 id="what-tolaria-uses-git-for" tabindex="-1">What Tolaria Uses Git For <a class="header-anchor" href="#what-tolaria-uses-git-for" aria-label="Permalink to &quot;What Tolaria Uses Git For&quot;">​</a></h2><ul><li>Whole-vault commit history.</li><li>Current diff for the vault.</li><li>Per-note history.</li><li>Current diff for an individual note.</li><li>Pull and push.</li><li>Conflict detection and resolution.</li><li>Remote connection for local-only vaults.</li></ul><h2 id="history-and-diffs" tabindex="-1">History And Diffs <a class="header-anchor" href="#history-and-diffs" aria-label="Permalink to &quot;History And Diffs&quot;">​</a></h2><p>Each note can show its own history and current diff, so you can understand how that file changed over time or what is unsaved relative to Git.</p><p>Tolaria also shows a history of the whole vault. Use it when you want to review broader changes across multiple notes before committing or syncing.</p><h2 id="local-commits" tabindex="-1">Local Commits <a class="header-anchor" href="#local-commits" aria-label="Permalink to &quot;Local Commits&quot;">​</a></h2><p>You can commit changes inside Tolaria without leaving the app. This gives you useful restore points even before a remote is configured.</p><h2 id="remotes" tabindex="-1">Remotes <a class="header-anchor" href="#remotes" aria-label="Permalink to &quot;Remotes&quot;">​</a></h2><p>Connect a compatible Git remote when you want sync or backup. Tolaria relies on your system Git authentication, so GitHub CLI, SSH keys, credential helpers, and existing Git configuration can continue to work.</p>',12)])])}const f=a(r,[["render",n]]);export{m as __pageData,f as default};
